// 候選＝在售 + 有照片 + 總價 ≥ 800 萬（2026-07-23 使用者定案：低於 800 萬不發）
// 排序新到舊；優先只挑「官網上架 30 天內」的新案，30 天內全發完了才放寬到較舊的案子
const MIN_PRICE = 800;      // 萬，含
const FRESH_DAYS = 30;      // 優先窗口
const body = $input.first().json;
const items = body.items || body.data || (Array.isArray(body) ? body : []);
const listedAt = x => new Date(x.houseol_created_at || x.created_at || 0).getTime();
const ageDays = x => (Date.now() - listedAt(x)) / 86400000;

const pool = items
  .filter(x => x && x.is_active === true && Number(x.image_count) > 0 && x.contract_no
    && Number(x.case_price) >= MIN_PRICE && Number(x.case_price) < 9999)
  .sort((a, b) => listedAt(b) - listedAt(a));

// 新案排前面、舊案墊後面：判重是下游做的，這樣「30 天內的都發過了」也不會空手而回
const fresh = pool.filter(x => ageDays(x) <= FRESH_DAYS);
const aged = pool.filter(x => ageDays(x) > FRESH_DAYS);
const picked = [...fresh, ...aged].slice(0, 40);

const cand = picked.map(x => ({ json: {
  keisId: x.id,
  contract_no: String(x.contract_no).toUpperCase(),
  case_name: x.case_name || '',
  official_url: x.official_url || '',
} }));
if (cand.length === 0) return [{ json: { _empty: true } }];
return cand;

// 一次撈回整批已建過的案件編號，比對候選（原本是每個候選打一次 Notion，40 次 → 1 次）
const res = $input.first().json;
const built = new Set(
  (res.results || [])
    .map(p => (p.properties?.['案件編號']?.rich_text?.[0]?.plain_text || '').toUpperCase().trim())
    .filter(Boolean)
);
return $('篩選候選').all().map(i => {
  const c = i.json;
  const no = String(c.contract_no || '').toUpperCase().trim();
  return { json: { ...c, _exists: !no || built.has(no) } };
});

// 白名單清洗：只留廣告欄位，屋主個資一律 drop
// 2026-07-23 KEIS 砍欄位後改版：official_url 改從列表帶、格局樓層自己組、屋齡學區交給永慶官網
const d = $input.first().json.data || $input.first().json;
const list = $('取 1 件').first().json || {};
const s = v => (v === null || v === undefined) ? '' : String(v).trim();
const num = v => (v === null || v === undefined || v === '') ? null : Number(v);
const r1 = v => (v === null || v === undefined || v === '') ? null : Math.round(Number(v) * 10) / 10;

const type = s(d.property_type);
const isLand = /土地|農|廠|車位/.test(type);

// 格局：只寫有數字的，全 0 或土地類就留白（KEIS 前端也是這樣顯示）
const parts = [[Number(d.room_count) || 0, '房'], [Number(d.living_count) || 0, '廳'], [Number(d.bathroom_count) || 0, '衛']];
const 格局 = isLand ? '' : parts.filter(p => p[0] > 0).map(p => p[0] + p[1]).join('');

// 樓層：起訖不同寫成範圍、地下室寫 B1、缺任一個就留白
const f = n => (n === null || n === undefined || n === '') ? null : (Number(n) < 0 ? 'B' + Math.abs(Number(n)) : String(Number(n)));
const a = f(d.floor_start), b = f(d.floor_end), t = f(d.total_floors);
let 樓層 = '';
if (!isLand && a && t) 樓層 = (b && b !== a ? a + '-' + b : a) + '/' + t;

const 賣點 = [d.feature_1, d.feature_2, d.feature_3, d.feature_4, d.feature_5].map(s).filter(Boolean);

return [{ json: {
  contract_no: s(d.contract_no).toUpperCase(),
  keisId: d.id,
  案名: s(d.case_name),
  總價萬: num(d.case_price),
  單價: num(d.unit_price),
  建物類型: type,
  格局,
  主建坪: r1(d.main_area),
  建物坪: r1(d.total_area),
  樓層,
  社區: s(d.community_name),
  地址: [s(d.property_address_city), s(d.property_address_district), s(d.property_address_road)].join(''),
  車位: [s(d.parking_type), s(d.parking_method)].filter(Boolean).join('/'),
  路名: s(d.property_address_road),
  行政區: s(d.property_address_district),
  專員: s(d.sales_agent_name),
  門市: s(d.store_name),
  official_url: s(list.official_url),
  賣點,
  機能: { 商圈: s(d.market_info), 捷運: s(d.mrt_station), 公園: s(d.park_info) },
}}];

