const 粉專footer = '\n\n📞 薛先生 0912877583（同 LINE）\nLINE：https://line.me/ti/p/kg1pMk4vX8\n\n—\n凱璿誼峰不動產有限公司\n經紀業特許字號：高市地政籍字第11034791100號\n證照字號：（111）登字第417208號';
